template <typename T>
class Trie01Vector {
private:
	struct TrieNode {
		array<int, 2> children;
		int cnt;
		TrieNode() : children{ 0, 0 }, cnt(0) {}
	};

	vector<TrieNode> tr;
	int newNode() { tr.push_back(TrieNode()); return ++nodeCnt; }

	int MAX; 	  
	int nodeCnt = 1;
	int root = 1;

public:
	Trie01Vector(int MAX) :MAX(MAX), tr(2) {}

	void insert(T num) {
		int now = root;
		tr[now].cnt++;

		// 枚举二进制数位
		for (int i = MAX; i >= 0; i--) {
			bool bit = (num >> i) & 1; // 当前数位
			if (not tr[now].children[bit]) {
				// 没有对应数位的边，则自己造边
				int tmp = newNode();
				tr[now].children[bit] = tmp;
			}
			now = tr[now].children[bit];
			tr[now].cnt++;
		}
	}

	// 遍历整个字典树进行操作
	int dfs(int now, int i, T pre) {
		// 左右子树
		var to = array<int, 2>{ tr[now].children[0], tr[now].children[1] };
		int ans = 0;

		// 遍历左右子树
		if (to[0] and to[1]) {
			ans += 1ll << i;
			ans += min(dfs(to[0], i - 1, pre), dfs(to[1], i - 1, pre + (1ll << i))) ;
		}
		else if (to[0]) {
			ans += dfs(to[0], i - 1, pre);
		}
		else if (to[1]) {
			ans += dfs(to[1], i - 1, pre + (1ll << i));
		}
		else  {
			// 遍历到底了，当前遍历到的数是 pre
		}
		return ans;
	}
	int query() {
		return dfs(root, MAX, 0);
	}
};

